```csharp
using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class IndexedDbStore : IInspectionStore
{
    private readonly IJSRuntime _js;
    private bool _initialized;

    public IndexedDbStore(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        if (_initialized) return;
        await _js.InvokeVoidAsync("indexedDb.initializeDb");
        _initialized = true;
    }

    public async Task<List<Site>> GetSitesAsync()
    {
        await EnsureInitializedAsync();
        return await _js.InvokeAsync<List<Site>>("indexedDb.getAllItems", "sites") ?? new();
    }

    public async Task<Site?> GetSiteAsync(string id)
    {
        await EnsureInitializedAsync();
        return await _js.InvokeAsync<Site?>("indexedDb.getItem", "sites", id);
    }

    public async Task SaveSiteAsync(Site site)
    {
        await EnsureInitializedAsync();
        await _js.InvokeVoidAsync("indexedDb.updateItem", "sites", site);
    }

    public async Task<List<Inspection>> GetInspectionsForSiteAsync(string siteId)
    {
        await EnsureInitializedAsync();
        return await _js.InvokeAsync<List<Inspection>>("indexedDb.getItemsByIndex", "inspections", "siteId", siteId) ?? new();
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        await EnsureInitializedAsync();
        return await _js.InvokeAsync<Inspection?>("indexedDb.getItem", "inspections", id);
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        await EnsureInitializedAsync();
        await _js.InvokeVoidAsync("indexedDb.updateItem", "inspections", inspection);
    }

    public async Task<List<ChecklistItem>> GetChecklistItemsAsync(string inspectionId)
    {
        await EnsureInitializedAsync();
        return await _js.InvokeAsync<List<ChecklistItem>>("indexedDb.getItemsByIndex", "checklistItems", "inspectionId", inspectionId) ?? new();
    }

    public async Task SaveChecklistItemAsync(ChecklistItem item)
    {
        await EnsureInitializedAsync();
        await _js.InvokeVoidAsync("indexedDb.updateItem", "checklistItems", item);
    }

    public async Task SaveChecklistItemsAsync(List<ChecklistItem> items)
    {
        await EnsureInitializedAsync();
        foreach (var item in items)
        {
            await _js.InvokeVoidAsync("indexedDb.updateItem", "checklistItems", item);
        }
    }

    public async Task<List<InspectionPhoto>> GetPhotosAsync(string inspectionId)
    {
        await EnsureInitializedAsync();
        return await _js.InvokeAsync<List<InspectionPhoto>>("indexedDb.getItemsByIndex", "photos", "inspectionId", inspectionId) ?? new();
    }

    public async Task SavePhotoAsync(InspectionPhoto photo)
    {
        await EnsureInitializedAsync();
        await _js.InvokeVoidAsync("indexedDb.updateItem", "photos", photo);
    }

    public async Task DeletePhotoAsync(string id)
    {
        await EnsureInitializedAsync();
        await _js.InvokeVoidAsync("indexedDb.deleteItem", "photos", id);
    }

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        await EnsureInitializedAsync();
        var all = await _js.InvokeAsync<List<Inspection>>("indexedDb.getAllItems", "inspections") ?? new();
        return all.Where(i => !i.IsSynced).ToList();
    }

    public async Task<List<InspectionPhoto>> GetUnsyncedPhotosAsync()
    {
        await EnsureInitializedAsync();
        var all = await _js.InvokeAsync<List<InspectionPhoto>>("indexedDb.getAllItems", "photos") ?? new();
        return all.Where(p => !p.IsSynced).ToList();
    }

    private async Task EnsureInitializedAsync()
    {
        if (!_initialized)
            await InitializeAsync();
    }
}
