```csharp
using SiteInspector.Client.Models;

namespace SiteInspector.Endpoints;

public static class SyncEndpoints
{
    public static void MapSyncEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/sync");

        group.MapPost("/inspections", (List<Inspection> inspections, InMemorySyncStore store) =>
        {
            store.Inspections.AddRange(inspections);
            return Results.Ok(new { synced = inspections.Count });
        });

        group.MapPost("/photos", (List<InspectionPhoto> photos, InMemorySyncStore store) =>
        {
            store.Photos.AddRange(photos);
            return Results.Ok(new { synced = photos.Count });
        });

        group.MapGet("/status", (InMemorySyncStore store) =>
        {
            return Results.Ok(new
            {
                inspectionCount = store.Inspections.Count,
                photoCount = store.Photos.Count
            });
        });
    }
}

public class InMemorySyncStore
{
    public List<Inspection> Inspections { get; } = new();
    public List<InspectionPhoto> Photos { get; } = new();
}
