@code {
    private List<Site>? _sites;
    private Dictionary<string, int> _inspectionCounts = new();
    private bool _showAddForm;
    private string _newSiteName = "";
    private string _newSiteAddress = "";

    protected override async Task OnInitializedAsync()
    {
        await Store.InitializeAsync();
        await LoadSites();
    }

    private async Task LoadSites()
    {
        _sites = await Store.GetSitesAsync();
        foreach (var site in _sites)
        {
            var inspections = await Store.GetInspectionsForSiteAsync(site.Id);
            _inspectionCounts[site.Id] = inspections.Count;
        }
    }

    private int GetInspectionCount(string siteId)
    {
        return _inspectionCounts.TryGetValue(siteId, out var count) ? count : 0;
    }

    private void ToggleAddForm() => _showAddForm = !_showAddForm;

