    protected override async Task OnInitializedAsync()
    {
        await Store.InitializeAsync();
        await LoadPhotos();
    }

    private async Task LoadPhotos()
    {
        _photos = await Store.GetPhotosAsync(InspectionId);
    }

    private async Task OnPhotoSelected(InputFileChangeEventArgs e)
    {
        var file = e.File;
        if (file == null) return;

        var buffer = new byte[file.Size];
        await file.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024).ReadAsync(buffer);
        var base64 = Convert.ToBase64String(buffer);

        var photo = new InspectionPhoto
        {
            InspectionId = InspectionId,
            FileName = file.Name,
            ContentType = file.ContentType,
            Base64Data = base64,
            CapturedAt = DateTime.UtcNow
        };

        await Store.SavePhotoAsync(photo);
        await LoadPhotos();
    }

    private void SelectPhoto(InspectionPhoto photo) => _selectedPhoto = photo;

    private async Task SaveCaption()
    {
        if (_selectedPhoto != null)
        {
            await Store.SavePhotoAsync(_selectedPhoto);
            _selectedPhoto = null;
        }
    }

    private async Task DeleteSelected()
    {
        if (_selectedPhoto != null)
        {
            await Store.DeletePhotoAsync(_selectedPhoto.Id);
            _selectedPhoto = null;
            await LoadPhotos();
        }
    }

