### 11. SiteInspector.Client/Services/SyncService.cs
```csharp
using System.Net.Http.Json;
using Microsoft.JSInterop;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class SyncService : ISyncService, IDisposable
{
    private readonly IInspectionStore _store;
    private readonly HttpClient _http;
    private readonly IJSRuntime _js;
    private Timer? _timer;

    public event Action<SyncStatus>? OnSyncStatusChanged;
    public SyncStatus CurrentStatus { get; private set; } = SyncStatus.Idle;
    public DateTime? LastSyncTime { get; private set; }

    public SyncService(IInspectionStore store, HttpClient http, IJSRuntime js)
    {
        _store = store;
        _http = http;
        _js = js;
        _timer = new Timer(async _ => await TryAutoSync(), null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(60));
    }

    public async Task<bool> IsOnlineAsync()
    {
        try
        {
            return await _js.InvokeAsync<bool>("eval", "navigator.onLine");
        }
        catch
        {
            return false;
        }
    }

    public async Task<SyncResult> SyncAsync()
    {
        var result = new SyncResult();

        try
        {
            if (!await IsOnlineAsync())
            {
                SetStatus(SyncStatus.Offline);
                result.ErrorMessage = "Device is offline";
                return result;
            }

            SetStatus(SyncStatus.Syncing);

            var inspections = await _store.GetUnsyncedInspectionsAsync();
            if (inspections.Any())
            {
                var response = await _http.PostAsJsonAsync("/api/sync/inspections", inspections);
                if (response.IsSuccessStatusCode)
                {
                    foreach (var inspection in inspections)
                    {
                        inspection.IsSynced = true;
                        await _store.SaveInspectionAsync(inspection);
                    }
                    result.InspectionsSynced = inspections.Count;
                }
            }

            var photos = await _store.GetUnsyncedPhotosAsync();
            if (photos.Any())
            {
                var response = await _http.PostAsJsonAsync("/api/sync/photos", photos);
                if (response.IsSuccessStatusCode)
                {
                    foreach (var photo in photos)
                    {
                        photo.IsSynced = true;
                        await _store.SavePhotoAsync(photo);
                    }
                    result.PhotosSynced = photos.Count;
                }
            }

            result.Success = true;
            LastSyncTime = DateTime.UtcNow;
            SetStatus(SyncStatus.Success);
        }
        catch (Exception ex)
        {
            result.ErrorMessage = ex.Message;
            SetStatus(SyncStatus.Error);
        }

        return result;
    }

    private async Task TryAutoSync()
    {
        try
        {
            if (await IsOnlineAsync())
            {
                await SyncAsync();
            }
        }
        catch
        {
            // Silent fail for auto-sync
        }
    }

    private void SetStatus(SyncStatus status)
    {
        CurrentStatus = status;
        OnSyncStatusChanged?.Invoke(status);
    }

    public void Dispose()
    {
        _timer?.Dispose();
    }
}
