    protected override async Task OnInitializedAsync()
    {
        try
        {
            var saved = await JS.InvokeAsync<string?>("localStorage.getItem", "inspectorName");
            if (!string.IsNullOrEmpty(saved))
                _inspectorName = saved;
        }
        catch { }
    }

    private async Task StartInspection()
    {
        if (string.IsNullOrWhiteSpace(_inspectorName)) return;

        await JS.InvokeVoidAsync("localStorage.setItem", "inspectorName", _inspectorName.Trim());

        var inspection = new Inspection
        {
            SiteId = SiteId,
            InspectorName = _inspectorName.Trim()
        };

        await Store.SaveInspectionAsync(inspection);

        var checklistItems = TemplateService.GetDefaultChecklist(inspection.Id);
        await Store.SaveChecklistItemsAsync(checklistItems);

        Navigation.NavigateTo($"/inspections/{inspection.Id}/checklist");
    }
