```razor
@page "/inspections/{InspectionId}/checklist"
@inject IInspectionStore Store
@inject NavigationManager Navigation

<div class="page-content">
    @if (_items == null)
    {
        <div class="loading">Loading...</div>
    }
    else
    {
        <div class="flex-between mb-sm">
            <h2>Checklist</h2>
            <span class="badge badge-secondary">@_checkedCount / @_items.Count</span>
        </div>

        <div class="progress-bar mb-md">
            <div class="progress-bar-fill" style="width: @GetProgressPercent()%"></div>
        </div>

        @foreach (var group in _items.GroupBy(i => i.Category))
        {
            <div class="card mb-sm">
                <div class="flex-between" @onclick="() => ToggleCategory(group.Key)" style="cursor:pointer;">
                    <h3>@group.Key</h3>
                    <span>@(_collapsedCategories.Contains(group.Key) ? "▶" : "▼")</span>
                </div>

                @if (!_collapsedCategories.Contains(group.Key))
                {
                    @foreach (var item in group)
                    {
                        <div class="checklist-item" style="padding: 10px 0; border-top: 1px solid var(--border);">
                            <p style="margin: 0 0 8px 0; font-size: 0.95rem;">@item.Description</p>
                            <div class="flex gap-sm">
                                <button class="checklist-btn pass @(item.Result == CheckResult.Pass ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.Pass)">✓ Pass</button>
                                <button class="checklist-btn fail @(item.Result == CheckResult.Fail ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.Fail)">✗ Fail</button>
                                <button class="checklist-btn na @(item.Result == CheckResult.NA ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.NA)">N/A</button>
                            </div>

                            @if (_expandedItems.Contains(item.Id))
                            {
                                <div class="mt-sm">
                                    <input placeholder="Add notes..." value="@item.Notes"
                                           @onchange="(e) => SaveNotes(item, e.Value?.ToString() ?? "")" />
                                </div>
                            }

                            <button class="btn-sm btn-secondary mt-sm" style="font-size:0.75rem; min-height:32px; padding:4px 8px;"
                                    @onclick="() => ToggleExpand(item.Id)">
                                @(_expandedItems.Contains(item.Id) ? "Hide Notes" : "📝 Notes")
                            </button>
                        </div>
                    }
                }
            </div>
        }

        <div class="grid gap-md mt-md">
            <button class="btn-primary" @onclick="GoToPhotos" style="width:100%">📷 Add Photos</button>
            <button class="btn-success" @onclick="CompleteInspection" style="width:100%">✅ Complete Inspection</button>
        </div>
    }
</div>

@code {
    [Parameter] public string InspectionId { get; set; } = "";

    private List<ChecklistItem>? _items;
    private int _checkedCount;
    private HashSet<string> _collapsedCategories = new();
    private HashSet<string> _expandedItems = new();

    protected override async Task OnInitializedAsync()
    {
        await Store.InitializeAsync();
        _items = await Store.GetChecklistItemsAsync(InspectionId);
        UpdateCount();
    }

    private void UpdateCount()
    {
        _checkedCount = _items?.Count(i => i.Result != CheckResult.NotChecked) ?? 0;
    }

    private int GetProgressPercent()
    {
        if (_items == null || _items.Count == 0) return 0;
        return (int)((double)_checkedCount / _items.Count * 100);
    }

    private async Task SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = result;
        item.CheckedAt = DateTime.UtcNow;
        await Store.SaveChecklistItemAsync(item);
        UpdateCount();
    }

    private async Task SaveNotes(ChecklistItem item, string notes)
    {
        item.Notes = notes;
        await Store.SaveChecklistItemAsync(item);
    }

    private void ToggleCategory(string category)
    {
        if (!_collapsedCategories.Remove(category))
            _collapsedCategories.Add(category);
    }

    private void ToggleExpand(string itemId)
    {
        if (!_expandedItems.Remove(itemId))
            _expandedItems.Add(itemId);
    }

    private void GoToPhotos() => Navigation.NavigateTo($"/inspections/{InspectionId}/photos");

    private async Task CompleteInspection()
    {
        Navigation.NavigateTo($"/inspections/{InspectionId}/summary");
    }
}
