### 13. CREATE SiteInspector.Client/Pages/SyncPage.razor:
```razor
@page "/sync"
@inject ISyncService SyncService
@inject IInspectionStore Store

<div class="page-content">
    <h2>Sync</h2>

    <div class="card mb-md text-center">
        <div class="flex-center gap-sm mb-sm">
            <span class="status-dot @GetStatusDotClass()"></span>
            <strong>@GetStatusText()</strong>
        </div>
        <p class="text-secondary">@_pendingInspections inspections, @_pendingPhotos photos pending</p>
    </div>

    <button class="btn-primary mb-md" @onclick="DoSync" disabled="@_isSyncing" style="width:100%">
        @(_isSyncing ? "⏳ Syncing..." : "🔄 Sync Now")
    </button>

    @if (_lastResult != null)
    {
        <div class="card @(_lastResult.Success ? "" : "text-danger")">
            @if (_lastResult.Success)
            {
                <p class="text-success">✓ Sync successful</p>
                <p class="text-secondary">@_lastResult.InspectionsSynced inspections, @_lastResult.PhotosSynced photos synced</p>
            }
            else
            {
                <p class="text-danger">✗ Sync failed</p>
                <p class="text-secondary">@_lastResult.ErrorMessage</p>
            }
        </div>
    }

    @if (SyncService.LastSyncTime.HasValue)
    {
        <p class="text-secondary text-center mt-md" style="font-size:0.85rem;">
            Last successful sync: @SyncService.LastSyncTime.Value.ToLocalTime().ToString("g")
        </p>
    }
</div>

@code {
    private bool _isSyncing;
    private int _pendingInspections;
    private int _pendingPhotos;
    private SyncResult? _lastResult;

    protected override async Task OnInitializedAsync()
    {
        await Store.InitializeAsync();
        await LoadPendingCounts();
    }

    private async Task LoadPendingCounts()
    {
        var inspections = await Store.GetUnsyncedInspectionsAsync();
        _pendingInspections = inspections.Count;
        var photos = await Store.GetUnsyncedPhotosAsync();
        _pendingPhotos = photos.Count;
    }

    private async Task DoSync()
    {
        _isSyncing = true;
        StateHasChanged();

        _lastResult = await SyncService.SyncAsync();

        _isSyncing = false;
        await LoadPendingCounts();
    }

    private string GetStatusDotClass() => SyncService.CurrentStatus switch
    {
        SyncStatus.Success => "green",
        SyncStatus.Syncing => "yellow",
        SyncStatus.Offline or SyncStatus.Error => "red",
        _ => "yellow"
    };

    private string GetStatusText() => SyncService.CurrentStatus switch
    {
        SyncStatus.Success => "Online - Synced",
        SyncStatus.Syncing => "Syncing...",
        SyncStatus.Offline => "Offline",
        SyncStatus.Error => "Sync Error",
        _ => "Ready"
    };
}
