window.indexedDb = {
    db: null,

    initializeDb: function () {
        return new Promise((resolve, reject) => {
            if (window.indexedDb.db) {
                resolve();
                return;
            }

            const request = window.indexedDB.open('SiteInspectorDb', 1);

            request.onupgradeneeded = function (event) {
                const db = event.target.result;

                if (!db.objectStoreNames.contains('sites')) {
                    db.createObjectStore('sites', { keyPath: 'id' });
                }

                if (!db.objectStoreNames.contains('inspections')) {
                    const inspectionStore = db.createObjectStore('inspections', { keyPath: 'id' });
                    inspectionStore.createIndex('siteId', 'siteId', { unique: false });
                }

                if (!db.objectStoreNames.contains('checklistItems')) {
                    const checklistStore = db.createObjectStore('checklistItems', { keyPath: 'id' });
                    checklistStore.createIndex('inspectionId', 'inspectionId', { unique: false });
                }

                if (!db.objectStoreNames.contains('photos')) {
                    const photoStore = db.createObjectStore('photos', { keyPath: 'id' });
                    photoStore.createIndex('inspectionId', 'inspectionId', { unique: false });
                }
            };

            request.onsuccess = function (event) {
                window.indexedDb.db = event.target.result;
                resolve();
            };

            request.onerror = function (event) {
                reject('Error opening IndexedDB: ' + event.target.error);
            };
        });
    },

    addItem: function (storeName, item) {
        return new Promise((resolve, reject) => {
            const transaction = window.indexedDb.db.transaction(storeName, 'readwrite');
            const store = transaction.objectStore(storeName);
            const request = store.add(item);
            request.onsuccess = () => resolve();
            request.onerror = (e) => reject('Error adding item: ' + e.target.error);
        });
    },

    updateItem: function (storeName, item) {
        return new Promise((resolve, reject) => {
            const transaction = window.indexedDb.db.transaction(storeName, 'readwrite');
            const store = transaction.objectStore(storeName);
            const request = store.put(item);
            request.onsuccess = () => resolve();
            request.onerror = (e) => reject('Error updating item: ' + e.target.error);
        });
    },

    getItem: function (storeName, id) {
        return new Promise((resolve, reject) => {
            const transaction = window.indexedDb.db.transaction(storeName, 'readonly');
            const store = transaction.objectStore(storeName);
            const request = store.get(id);
            request.onsuccess = () => resolve(request.result || null);
            request.onerror = (e) => reject('Error getting item: ' + e.target.error);
        });
    },

    getAllItems: function (storeName) {
        return new Promise((resolve, reject) => {
            const transaction = window.indexedDb.db.transaction(storeName, 'readonly');
            const store = transaction.objectStore(storeName);
            const request = store.getAll();
            request.onsuccess = () => resolve(request.result || []);
            request.onerror = (e) => reject('Error getting all items: ' + e.target.error);
        });
    },

    getItemsByIndex: function (storeName, indexName, value) {
        return new Promise((resolve, reject) => {
            const transaction = window.indexedDb.db.transaction(storeName, 'readonly');
            const store = transaction.objectStore(storeName);
            const index = store.index(indexName);
            const request = index.getAll(value);
            request.onsuccess = () => resolve(request.result || []);
            request.onerror = (e) => reject('Error getting items by index: ' + e.target.error);
