@inherits LayoutComponentBase
@inject ISyncService SyncService
@inject NavigationManager Navigation

<div class="app-layout">
    <header class="top-bar">
        <div class="top-bar-content">
            <h1 class="app-title">Site Inspector</h1>
            <div class="sync-indicator">
                <span class="status-dot @GetSyncDotClass()"></span>
            </div>
        </div>
    </header>

    <main class="main-content">
        @Body
    </main>

    <nav class="bottom-nav">
        <a class="nav-item @GetActiveClass("sites")" href="/sites">
            <span class="nav-icon">🏗️</span>
            <span class="nav-label">Sites</span>
        </a>
        <a class="nav-item @GetActiveClass("")" href="/">
            <span class="nav-icon">📋</span>
            <span class="nav-label">Home</span>
        </a>
        <a class="nav-item @GetActiveClass("sync")" href="/sync">
            <span class="nav-icon">🔄</span>
            <span class="nav-label">Sync</span>
        </a>
    </nav>
</div>

@code {
    private SyncStatus _syncStatus = SyncStatus.Idle;

    protected override void OnInitialized()
    {
        SyncService.OnSyncStatusChanged += HandleSyncStatusChanged;
    }

    private void HandleSyncStatusChanged(SyncStatus status)
    {
        _syncStatus = status;
        InvokeAsync(StateHasChanged);
    }

    private string GetSyncDotClass() => _syncStatus switch
    {
        SyncStatus.Success => "green",
        SyncStatus.Syncing => "yellow",
        SyncStatus.Offline or SyncStatus.Error => "red",
        _ => "yellow"
    };

    private string GetActiveClass(string segment)
    {
        var uri = Navigation.Uri;
        var relativePath = Navigation.ToBaseRelativePath(uri);
        if (segment == "" && relativePath == "") return "active";
        if (segment != "" && relativePath.StartsWith(segment)) return "active";
        return "";
    }

    public void Dispose()
    {
        SyncService.OnSyncStatusChanged -= HandleSyncStatusChanged;
    }
}

