@page "/"
@inject IInspectionStore Store
@inject ISyncService SyncService
@inject NavigationManager Navigation

<div class="page-content">
    <div class="text-center mb-md">
        <h2>Welcome, Inspector</h2>
        <p class="text-secondary">Construction site safety checklist app</p>
    </div>

    <div class="grid grid-2 mb-md">
        <div class="card text-center">
            <div style="font-size: 2rem;">🏗️</div>
            <div style="font-size: 1.5rem; font-weight: bold;">@_siteCount</div>
            <div class="text-secondary">Sites</div>
        </div>
        <div class="card text-center">
            <div style="font-size: 2rem;">⏳</div>
            <div style="font-size: 1.5rem; font-weight: bold;">@_pendingCount</div>
            <div class="text-secondary">Pending Sync</div>
        </div>
    </div>

    <div class="grid gap-md">
        <button class="btn-primary" @onclick="NavigateToSites" style="width:100%">
            🏗️ View Sites
        </button>
        <button class="btn-success" @onclick="StartNewInspection" style="width:100%">
            ➕ New Inspection
        </button>
    </div>

    @if (SyncService.LastSyncTime.HasValue)
    {
        <p class="text-secondary text-center mt-md" style="font-size: 0.85rem;">
            Last synced: @SyncService.LastSyncTime.Value.ToLocalTime().ToString("g")
        </p>
    }
</div>

@code {
    private int _siteCount;
    private int _pendingCount;

    protected override async Task OnInitializedAsync()
    {
        await Store.InitializeAsync();
        var sites = await Store.GetSitesAsync();
        _siteCount = sites.Count;
        var unsynced = await Store.GetUnsyncedInspectionsAsync();
        _pendingCount = unsynced.Count;
    }

    private void NavigateToSites() => Navigation.NavigateTo("/sites");

    private void StartNewInspection()
    {
        Navigation.NavigateTo("/sites");
    }
}

@page "/sites"
@inject IInspectionStore Store
@inject NavigationManager Navigation

<div class="page-content">
    <div class="flex-between mb-md">
        <h2>Sites</h2>
        <button class="btn-primary btn-sm" @onclick="ToggleAddForm">➕ Add Site</button>
    </div>

    @if (_showAddForm)
    {
        <div class="card mb-md">
            <div class="form-group">
                <label>Site Name</label>
                <input @bind="_newSiteName" placeholder="Enter site name" />
            </div>
            <div class="form-group">
                <label>Address</label>
                <input @bind="_newSiteAddress" placeholder="Enter address" />
            </div>
            <div class="flex gap-sm">
                <button class="btn-success" @onclick="AddSite" style="flex:1">Save</button>
                <button class="btn-secondary" @onclick="ToggleAddForm" style="flex:1">Cancel</button>
            </div>
        </div>
    }

    @if (_sites == null)
    {
        <div class="loading">Loading...</div>
    }
    else if (!_sites.Any())
    {
        <div class="card text-center">
            <p class="text-secondary">No sites yet. Add your first construction site!</p>
        </div>
    }
    else
    {
        @foreach (var site in _sites)
        {
            <div class="card card-clickable" @onclick="() => ViewSite(site.Id)">
                <h3>@site.Name</h3>
                <p class="text-secondary" style="margin:4px 0; font-size:0.9rem;">@site.Address</p>
                <span class="badge badge-secondary">@GetInspectionCount(site.Id) inspections</span>
            </div>
        }
    }
</div>

@code {
    private List<Site>? _sites;
    private Dictionary<string, int> _inspectionCounts = new();
    private bool _showAddForm;
    private string _newSiteName = "";
    private string _newSiteAddress = "";

    protected override async Task OnInitializedAsync()
    {
        await Store.InitializeAsync();
        await LoadSites();
    }

    private async Task LoadSites()
    {
        _sites = await Store.GetSitesAsync();
        foreach (var site in _sites)
        {
            var inspections = await Store.GetInspectionsForSiteAsync(site.Id);
            _inspectionCounts[site.Id] = inspections.Count;
        }
    }

    private int GetInspectionCount(string siteId)
    {
        return _inspectionCounts.TryGetValue(siteId, out var count) ? count : 0;
    }

    private void ToggleAddForm() => _showAddForm = !_showAddForm;

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;

        var site = new Site
        {
            Name = _newSiteName.Trim(),
            Address = _newSiteAddress.Trim()
        };

        await Store.SaveSiteAsync(site);
        _newSiteName = "";
        _newSiteAddress = "";
        _showAddForm = false;
        await LoadSites();
    }

    private void ViewSite(string id) => Navigation.NavigateTo($"/sites/{id}");
}

@page "/sites/{SiteId}"
@inject IInspectionStore Store
@inject NavigationManager Navigation

<div class="page-content">
    @if (_site == null)
    {
        <div class="loading">Loading...</div>
    }
    else
    {
        <h2>@_site.Name</h2>
        <p class="text-secondary mb-md">@_site.Address</p>

        <button class="btn-success mb-md" @onclick="StartInspection" style="width:100%">
            🔍 Start New Inspection
        </button>

        <h3 class="mb-sm">Inspections</h3>

        @if (!_inspections.Any())
        {
            <div class="card text-center">
                <p class="text-secondary">No inspections yet for this site.</p>
            </div>
        }
        else
        {
            @foreach (var inspection in _inspections.OrderByDescending(i => i.StartedAt))
            {
                <div class="card card-clickable" @onclick="() => ViewInspection(inspection)">
                    <div class="flex-between">
                        <strong>@inspection.InspectorName</strong>
                        <span class="badge @(inspection.Status == InspectionStatus.Completed ? "badge-success" : "badge-warning")">
                            @inspection.Status
                        </span>
                    </div>
                    <p class="text-secondary" style="margin:4px 0; font-size:0.85rem;">
                        @inspection.StartedAt.ToLocalTime().ToString("g")
                    </p>
                    @if (!inspection.IsSynced)
                    {
                        <span class="badge badge-warning">Not synced</span>
                    }
                </div>
            }
        }
    }
</div>

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private Site? _site;
    private List<Inspection> _inspections = new();

    protected override async Task OnInitializedAsync()
    {
        await Store.InitializeAsync();
        _site = await Store.GetSiteAsync(SiteId);
        _inspections = await Store.GetInspectionsForSiteAsync(SiteId);
    }

    private void StartInspection() => Navigation.NavigateTo($"/inspections/new/{SiteId}");

    private void ViewInspection(Inspection inspection)
    {
        if (inspection.Status == InspectionStatus.InProgress)
            Navigation.NavigateTo($"/inspections/{inspection.Id}/checklist");
        else
            Navigation.NavigateTo($"/inspections/{inspection.Id}/summary");
    }
}

@page "/inspections/new/{SiteId}"
@inject IInspectionStore Store
@inject ChecklistTemplateService TemplateService
@inject NavigationManager Navigation
@inject IJSRuntime JS

<div class="page-content">
    <h2>New Inspection</h2>

    <div class="card mt-md">
        <div class="form-group">
            <label>Inspector Name</label>
            <input @bind="_inspectorName" placeholder="Your name" />
        </div>

        <p class="text-secondary" style="font-size:0.85rem;">
            📋 24 checklist items across 6 categories will be created.
        </p>

        <button class="btn-success mt-md" @onclick="StartInspection" style="width:100%"
                disabled="@string.IsNullOrWhiteSpace(_inspectorName)">
            🚀 Start Inspection
        </button>
    </div>
</div>

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private string _inspectorName = "";

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var saved = await JS.InvokeAsync<string?>("localStorage.getItem", "inspectorName");
            if (!string.IsNullOrEmpty(saved))
                _inspectorName = saved;
        }
        catch { }
    }

    private async Task StartInspection()
    {
        if (string.IsNullOrWhiteSpace(_inspectorName)) return;

        await JS.InvokeVoidAsync("localStorage.setItem", "inspectorName", _inspectorName.Trim());

        var inspection = new Inspection
        {
            SiteId = SiteId,
            InspectorName = _inspectorName.Trim()
        };

        await Store.SaveInspectionAsync(inspection);

        var checklistItems = TemplateService.GetDefaultChecklist(inspection.Id);
        await Store.SaveChecklistItemsAsync(checklistItems);

        Navigation.NavigateTo($"/inspections/{inspection.Id}/checklist");
    }
}

@page "/inspections/{InspectionId}/checklist"
@inject IInspectionStore Store
@inject NavigationManager Navigation

<div class="page-content">
    @if (_items == null)
    {
        <div class="loading">Loading...</div>
    }
    else
    {
        <div class="flex-between mb-sm">
            <h2>Checklist</h2>
            <span class="badge badge-secondary">@_checkedCount / @_items.Count</span>
        </div>

        <div class="progress-bar mb-md">
            <div class="progress-bar-fill" style="width: @GetProgressPercent()%"></div>
        </div>

        @foreach (var group in _items.GroupBy(i => i.Category))
        {
            <div class="card mb-sm">
                <div class="flex-between" @onclick="() => ToggleCategory(group.Key)" style="cursor:pointer;">
                    <h3>@group.Key</h3>
                    <span>@(_collapsedCategories.Contains(group.Key) ? "▶" : "▼")</span>
                </div>

                @if (!_collapsedCategories.Contains(group.Key))
                {
                    @foreach (var item in group)
                    {
                        <div class="checklist-item" style="padding: 10px 0; border-top: 1px solid var(--border);">
                            <p style="margin: 0 0 8px 0; font-size: 0.95rem;">@item.Description</p>
                            <div class="flex gap-sm">
                                <button class="checklist-btn pass @(item.Result == CheckResult.Pass ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.Pass)">✓ Pass</button>
                                <button class="checklist-btn fail @(item.Result == CheckResult.Fail ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.Fail)">✗ Fail</button>
                                <button class="checklist-btn na @(item.Result == CheckResult.NA ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.NA)">N/A</button>
                            </div>

                            @if (_expandedItems.Contains(item.Id))
                            {
                                <div class="mt-sm">
                                    <input placeholder="Add notes..." value="@item.Notes"
                                           @onchange="(e) => SaveNotes(item, e.Value?.ToString() ?? "")" />
                                </div>
                            }

                            <button class="btn-sm btn-secondary mt-sm" style="font-size:0.75rem; min-height:32px; padding:4px 8px;"
                                    @onclick="() => ToggleExpand(item.Id)">
                                @(_expandedItems.Contains(item.Id) ? "Hide Notes" : "📝 Notes")
                            </button>
                        </div>
                    }
                }
            </div>
        }

        <div class="grid gap-md mt-md">
            <button class="btn-primary" @onclick="GoToPhotos" style="width:100%">📷 Add Photos</button>
            <button class="btn-success" @onclick="CompleteInspection" style="width:100%">✅ Complete Inspection</button>
        </div>
    }
</div>

@code {
    [Parameter] public string InspectionId { get; set; } = "";

    private List<ChecklistItem>? _items;
    private int _checkedCount;
    private HashSet<string> _collapsedCategories = new();
    private HashSet<string> _expandedItems = new();

    protected override async Task OnInitializedAsync()
    {
        await Store.InitializeAsync();
        _items = await Store.GetChecklistItemsAsync(InspectionId);
        UpdateCount();
    }

    private void UpdateCount()
    {
        _checkedCount = _items?.Count(i => i.Result != CheckResult.NotChecked) ?? 0;
    }

    private int GetProgressPercent()
    {
        if (_items == null || _items.Count == 0) return 0;
        return (int)((double)_checkedCount / _items.Count * 100);
    }

    private async Task SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = result;
        item.CheckedAt = DateTime.UtcNow;
        await Store.SaveChecklistItemAsync(item);
        UpdateCount();
    }

    private async Task SaveNotes(ChecklistItem item, string notes)
    {
        item.Notes = notes;
        await Store.SaveChecklistItemAsync(item);
    }

    private void ToggleCategory(string category)
    {
        if (!_collapsedCategories.Remove(category))
            _collapsedCategories.Add(category);
    }

    private void ToggleExpand(string itemId)
    {
        if (!_expandedItems.Remove(itemId))
            _expandedItems.Add(itemId);
    }

    private void GoToPhotos() => Navigation.NavigateTo($"/inspections/{InspectionId}/photos");

    private async Task CompleteInspection()
    {
        Navigation.NavigateTo($"/inspections/{InspectionId}/summary");
    }
}

@page "/inspections/{InspectionId}/photos"
@inject IInspectionStore Store
@inject IJSRuntime JS
@inject NavigationManager Navigation

<div class="page-content">
    <div class="flex-between mb-md">
        <h2>Photos</h2>
        <button class="btn-secondary btn-sm" @onclick="GoBack">← Back</button>
    </div>

    <div class="card mb-md">
        <label class="btn-primary" style="width:100%; display:flex; align-items:center; justify-content:center; cursor:pointer;">
            📷 Capture Photo
            <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment"
                       style="display:none;" />
        </label>
    </div>

    @if (_photos.Any())
    {
        <div class="photo-grid">
            @foreach (var photo in _photos)
            {
                <div class="photo-thumb" @onclick="() => SelectPhoto(photo)">
                    <img src="data:@photo.ContentType;base64,@photo.Base64Data" alt="@photo.Caption" />
                </div>
            }
        </div>
    }
    else
    {
        <div class="card text-center">
            <p class="text-secondary">No photos yet. Tap the button above to capture.</p>
        </div>
    }

    @if (_selectedPhoto != null)
    {
        <div class="card mt-md">
            <img src="data:@_selectedPhoto.ContentType;base64,@_selectedPhoto.Base64Data"
                 style="width:100%; border-radius:8px; margin-bottom:12px;" alt="Selected" />
            <div class="form-group">
                <label>Caption</label>
                <input @bind="_selectedPhoto.Caption" placeholder="Add caption..." />
            </div>
            <div class="flex gap-sm">
                <button class="btn-primary" @onclick="SaveCaption" style="flex:1">Save</button>
                <button class="btn-danger" @onclick="DeleteSelected" style="flex:1">Delete</button>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public string InspectionId { get; set; } = "";

    private List<InspectionPhoto> _photos = new();
    private InspectionPhoto? _selectedPhoto;

    protected override async Task OnInitializedAsync()
    {
        await Store.InitializeAsync();
        await LoadPhotos();
    }

    private async Task LoadPhotos()
    {
        _photos = await Store.GetPhotosAsync(InspectionId);
    }

    private async Task OnPhotoSelected(InputFileChangeEventArgs e)
    {
        var file = e.File;
        if (file == null) return;

        var buffer = new byte[file.Size];
        await file.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024).ReadAsync(buffer);
        var base64 = Convert.ToBase64String(buffer);

        var photo = new InspectionPhoto
        {
            InspectionId = InspectionId,
            FileName = file.Name,
            ContentType = file.ContentType,
            Base64Data = base64,
            CapturedAt = DateTime.UtcNow
        };

        await Store.SavePhotoAsync(photo);
        await LoadPhotos();
    }

    private void SelectPhoto(InspectionPhoto photo) => _selectedPhoto = photo;

    private async Task SaveCaption()
    {
        if (_selectedPhoto != null)
        {
            await Store.SavePhotoAsync(_selectedPhoto);
            _selectedPhoto = null;
        }
    }

    private async Task DeleteSelected()
    {
        if (_selectedPhoto != null)
        {
            await Store.DeletePhotoAsync(_selectedPhoto.Id);
            _selectedPhoto = null;
            await LoadPhotos();
        }
    }

    private void GoBack() => Navigation.NavigateTo($"/inspections/{InspectionId}/checklist");
}

