                <div class="flex-between" @onclick="() => ToggleCategory(group.Key)" style="cursor:pointer;">
                    <h3>@group.Key</h3>
                    <span>@(_collapsedCategories.Contains(group.Key) ? "▶" : "▼")</span>
                </div>

                @if (!_collapsedCategories.Contains(group.Key))
                {
                    @foreach (var item in group)
                    {
                        <div class="checklist-item" style="padding: 10px 0; border-top: 1px solid var(--border);">
                            <p style="margin: 0 0 8px 0; font-size: 0.95rem;">@item.Description</p>
                            <div class="flex gap-sm">
                                <button class="checklist-btn pass @(item.Result == CheckResult.Pass ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.Pass)">✓ Pass</button>
                                <button class="checklist-btn fail @(item.Result == CheckResult.Fail ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.Fail)">✗ Fail</button>
                                <button class="checklist-btn na @(item.Result == CheckResult.NA ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.NA)">N/A</button>
                            </div>

                            @if (_expandedItems.Contains(item.Id))
                            {
                                <div class="mt-sm">
                                    <input placeholder="Add notes..." value="@item.Notes"
                                           @onchange="(e) => SaveNotes(item, e.Value?.ToString() ?? "")" />
                                </div>
