                                    @onclick="() => ToggleExpand(item.Id)">
                                @(_expandedItems.Contains(item.Id) ? "Hide Notes" : "📝 Notes")
                            </button>
                        </div>
                    }
                }
            </div>
        }

        <div class="grid gap-md mt-md">
            <button class="btn-primary" @onclick="GoToPhotos" style="width:100%">📷 Add Photos</button>
            <button class="btn-success" @onclick="CompleteInspection" style="width:100%">✅ Complete Inspection</button>
        </div>
    }
