                <div class="text-success" style="font-size:1.5rem; font-weight:bold;">@_passCount</div>
                <div class="text-secondary">Passed</div>
            </div>
            <div class="card text-center">
                <div class="text-danger" style="font-size:1.5rem; font-weight:bold;">@_failCount</div>
                <div class="text-secondary">Failed</div>
            </div>
        </div>

        <div class="card mb-md text-center">
            <span class="text-secondary">N/A: @_naCount</span> · 
            <span class="text-secondary">Unchecked: @_uncheckedCount</span>
        </div>

        @if (_failedItems.Any())
        {
            <h3 class="mb-sm text-danger">⚠️ Failed Items</h3>
            @foreach (var item in _failedItems)
            {
                <div class="card" style="border-left: 3px solid var(--danger);">
                    <strong>@item.Category</strong>
                    <p style="margin:4px 0;">@item.Description</p>
                    @if (!string.IsNullOrEmpty(item.Notes))
                    {
                        <p class="text-secondary" style="font-size:0.85rem;">📝 @item.Notes</p>
                    }
                </div>
            }
        }

        @if (_photos.Any())
        {
            <h3 class="mt-md mb-sm">📷 Photos (@_photos.Count)</h3>
            <div class="photo-grid mb-md">
                @foreach (var photo in _photos)
                {
                    <div class="photo-thumb">
                        <img src="data:@photo.ContentType;base64,@photo.Base64Data" alt="@photo.Caption" />
                    </div>
                }
            </div>
        }

        <div class="form-group">
            <label>Notes</label>
            <textarea rows="3" @bind="_inspection.Notes" placeholder="Add inspection notes..."></textarea>
        </div>

        @if (_inspection.Status == InspectionStatus.InProgress)
        {
            <div class="grid gap-md">
                <button class="btn-primary" @onclick="GoToChecklist" style="width:100%">← Back to Checklist</button>
                <button class="btn-success" @onclick="MarkComplete" style="width:100%">✅ Mark Complete</button>
            </div>
        }
        else
        {
            <div class="card text-center">
                <span class="badge badge-success">Completed</span>
                @if (!_inspection.IsSynced)
                {
                    <span class="badge badge-warning" style="margin-left:8px;">Pending Sync</span>
                }
            </div>
        }
    }
</div>

@code {
    [Parameter] public string InspectionId { get; set; } = "";

    private Inspection? _inspection;
    private List<ChecklistItem> _items = new();
    private List<InspectionPhoto> _photos = new();
    private List<ChecklistItem> _failedItems = new();
    private int _passCount, _failCount, _naCount, _uncheckedCount;

    protected override async Task OnInitializedAsync()
    {
        await Store.InitializeAsync();
        _inspection = await Store.GetInspectionAsync(InspectionId);
        _items = await Store.GetChecklistItemsAsync(InspectionId);
        _photos = await Store.GetPhotosAsync(InspectionId);

        _passCount = _items.Count(i => i.Result == CheckResult.Pass);
        _failCount = _items.Count(i => i.Result == CheckResult.Fail);
        _naCount = _items.Count(i => i.Result == CheckResult.NA);
        _uncheckedCount = _items.Count(i => i.Result == CheckResult.NotChecked);
        _failedItems = _items.Where(i => i.Result == CheckResult.Fail).ToList();
    }

    private void GoToChecklist() => Navigation.NavigateTo($"/inspections/{InspectionId}/checklist");

    private async Task MarkComplete()
    {
        if (_inspection == null) return;
        _inspection.Status = InspectionStatus.Completed;
        _inspection.CompletedAt = DateTime.UtcNow;
        await Store.SaveInspectionAsync(_inspection);
        StateHasChanged();
    }
}

@page "/sync"
@inject ISyncService SyncService
@inject IInspectionStore Store

<div class="page-content">
    <h2>Sync</h2>

    <div class="card mb-md text-center">
        <div class="flex-center gap-sm mb-sm">
            <span class="status-dot @GetStatusDotClass()"></span>
            <strong>@GetStatusText()</strong>
        </div>
        <p class="text-secondary">@_pendingInspections inspections, @_pendingPhotos photos pending</p>
    </div>

    <button class="btn-primary mb-md" @onclick="DoSync" disabled="@_isSyncing" style="width:100%">
        @(_isSyncing ? "⏳ Syncing..." : "🔄 Sync Now")
    </button>

    @if (_lastResult != null)
    {
        <div class="card @(_lastResult.Success ? "" : "text-danger")">
            @if (_lastResult.Success)
            {
                <p class="text-success">✓ Sync successful</p>
                <p class="text-secondary">@_lastResult.InspectionsSynced inspections, @_lastResult.PhotosSynced photos synced</p>
            }
            else
            {
                <p class="text-danger">✗ Sync failed</p>
                <p class="text-secondary">@_lastResult.ErrorMessage</p>
            }
        </div>
    }

    @if (SyncService.LastSyncTime.HasValue)
    {
        <p class="text-secondary text-center mt-md" style="font-size:0.85rem;">
            Last successful sync: @SyncService.LastSyncTime.Value.ToLocalTime().ToString("g")
        </p>
    }
</div>

@code {
    private bool _isSyncing;
    private int _pendingInspections;
    private int _pendingPhotos;
    private SyncResult? _lastResult;

    protected override async Task OnInitializedAsync()
    {
        await Store.InitializeAsync();
        await LoadPendingCounts();
    }

    private async Task LoadPendingCounts()
    {
        var inspections = await Store.GetUnsyncedInspectionsAsync();
        _pendingInspections = inspections.Count;
        var photos = await Store.GetUnsyncedPhotosAsync();
        _pendingPhotos = photos.Count;
    }

    private async Task DoSync()
    {
        _isSyncing = true;
        StateHasChanged();

        _lastResult = await SyncService.SyncAsync();

        _isSyncing = false;
        await LoadPendingCounts();
    }

    private string GetStatusDotClass() => SyncService.CurrentStatus switch
    {
        SyncStatus.Success => "green",
        SyncStatus.Syncing => "yellow",
        SyncStatus.Offline or SyncStatus.Error => "red",
        _ => "yellow"
    };

    private string GetStatusText() => SyncService.CurrentStatus switch
    {
        SyncStatus.Success => "Online - Synced",
        SyncStatus.Syncing => "Syncing...",
        SyncStatus.Offline => "Offline",
        SyncStatus.Error => "Sync Error",
        _ => "Ready"
    };
}

