+                @if (!_inspection.IsSynced)
+                {
+                    <span class="badge badge-warning" style="margin-left:8px;">Pending Sync</span>
+                }
+            </div>
+        }
+    }
+</div>
+
+@code {
+    [Parameter] public string InspectionId { get; set; } = "";
+
+    private Inspection? _inspection;
+    private List<ChecklistItem> _items = new();
+    private List<InspectionPhoto> _photos = new();
+    private List<ChecklistItem> _failedItems = new();
+    private int _passCount, _failCount, _naCount, _uncheckedCount;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await Store.InitializeAsync();
+        _inspection = await Store.GetInspectionAsync(InspectionId);
+        _items = await Store.GetChecklistItemsAsync(InspectionId);
+        _photos = await Store.GetPhotosAsync(InspectionId);
+
+        _passCount = _items.Count(i => i.Result == CheckResult.Pass);
+        _failCount = _items.Count(i => i.Result == CheckResult.Fail);
+        _naCount = _items.Count(i => i.Result == CheckResult.NA);
+        _uncheckedCount = _items.Count(i => i.Result == CheckResult.NotChecked);
+        _failedItems = _items.Where(i => i.Result == CheckResult.Fail).ToList();
+    }
+
+    private void GoToChecklist() => Navigation.NavigateTo($"/inspections/{InspectionId}/checklist");
+
+    private async Task MarkComplete()
+    {
+        if (_inspection == null) return;
+        _inspection.Status = InspectionStatus.Completed;
+        _inspection.CompletedAt = DateTime.UtcNow;
+        await Store.SaveInspectionAsync(_inspection);
+        StateHasChanged();
+    }
+}
